import{_ as s,o as e,c as a,a as n}from"./app.42c4a044.js";const u=JSON.parse('{"title":"Install","description":"","frontmatter":{},"headers":[{"level":2,"title":"环境要求","slug":"环境要求","link":"#环境要求","children":[]},{"level":2,"title":"国内镜像","slug":"国内镜像","link":"#国内镜像","children":[]},{"level":2,"title":"Composer 安装","slug":"composer-安装","link":"#composer-安装","children":[{"level":3,"title":"安装","slug":"安装","link":"#安装","children":[]},{"level":3,"title":"运行","slug":"运行","link":"#运行","children":[]}]},{"level":2,"title":"基础配置","slug":"基础配置","link":"#基础配置","children":[{"level":3,"title":"入口目录","slug":"入口目录","link":"#入口目录","children":[]},{"level":3,"title":"目录权限","slug":"目录权限","link":"#目录权限","children":[]}]},{"level":2,"title":"搭建站点","slug":"搭建站点","link":"#搭建站点","children":[{"level":3,"title":"Apache","slug":"apache","link":"#apache","children":[]}]}],"relativePath":"docs/started/install.md"}'),l={name:"docs/started/install.md"},p=n(`<h1 id="install" tabindex="-1">Install <a class="header-anchor" href="#install">¶</a></h1><div class="tip custom-block"><p class="custom-block-title">Testing Is Documentation</p><p><a href="https://github.com/hunzhiwange/framework/blob/master/tests/Docs/Started/InstallDoc.php" target="_blank" rel="noreferrer">tests/Docs/Started/InstallDoc.php</a></p></div><p>QueryPHP 是一个渐进式 PHP 常驻框架，我们强调的是一个渐进式，它既可以运行在 PHP-FPM 场景，同时还支持在 RoadRunner 服务中运行。</p><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求">¶</a></h2><p>事实上，QueryPHP 也是一个普通的 PHP 框架，目前最低版本要求 PHP 7.4.0，我们对环境并没有特别的要求。</p><ul><li>PHP ^7.4.0</li><li>ext-mbstring <a href="https://github.com/hunzhiwange/framework/blob/master/src/Leevel/Support/Str.php" target="_blank" rel="noreferrer">字符处理</a></li><li>ext-openssl <a href="https://github.com/hunzhiwange/framework/blob/master/src/Leevel/Encryption/Encryption.php" target="_blank" rel="noreferrer">加密组件</a></li></ul><p>我们系统依赖的组件可以通过 <a href="https://github.com/hunzhiwange/queryphp/blob/master/composer.json" target="_blank" rel="noreferrer">composer.json</a> 找到，我们提供了大量开箱即用的功能。</p><p>实际上，QueryPHP 对于环境来说<code>只需要</code>安装一个 <code>PHP 8.1.0</code> 及以上版本即可，这个时候甚至无需安装 Nginx 而使用 PHP 内置 WebServer 即可将 QueryPHP 跑起来。</p><p>对于每位 PHP 工程师来说，您的电脑早已经运行着一个 PHP 7 版本，接着您可以进行安装了。</p><h2 id="国内镜像" tabindex="-1">国内镜像 <a class="header-anchor" href="#国内镜像">¶</a></h2><p>QueryPHP 使用 <a href="https://developer.aliyun.com/composer" target="_blank" rel="noreferrer">Composer</a> 来管理整个项目依赖，因此确保您已经安装了 Composer。</p><p>国外镜像访问速度很慢，我们建议使用国内阿里云镜像。</p><ul><li>镜像 1 <a href="https://developer.aliyun.com/composer" target="_blank" rel="noreferrer">https://developer.aliyun.com/composer</a></li></ul><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">composer</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-g</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repo.packagist</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">composer</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://mirrors.aliyun.com/composer/</span></span>
<span class="line"></span></code></pre></div><h2 id="composer-安装" tabindex="-1">Composer 安装 <a class="header-anchor" href="#composer-安装">¶</a></h2><p>你可以在终端中运行 <code>create-project</code> 命令来安装 QueryPHP.</p><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装">¶</a></h3><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">composer</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">create-project</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--prefer-dist</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">hunzhiwange/queryphp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">myapp</span></span>
<span class="line"></span></code></pre></div><p>或者体验开发版本</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">composer</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">create-project</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">hunzhiwange/queryphp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">myapp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">dev-master</span></span>
<span class="line"></span></code></pre></div><h3 id="运行" tabindex="-1">运行 <a class="header-anchor" href="#运行">¶</a></h3><p>你也可以简单实用 PHP 内置的服务器来运行 QueryPHP,当然更好的选择配置 Nginx 站点。</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">php</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">leevel</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">server</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#C3E88D;">Visite</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">http://127.0.0.1:</span><span style="color:#F78C6C;">9527</span><span style="color:#A6ACCD;">/</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><ul><li>首页 <a href="http://127.0.0.1:9527/" target="_blank" rel="noreferrer">http://127.0.0.1:9527/</a></li><li>MVC 路由 <a href="http://127.0.0.1:9527/api/test" target="_blank" rel="noreferrer">http://127.0.0.1:9527/api/test</a></li><li>MVC restful 路由 <a href="http://127.0.0.1:9527/restful/123" target="_blank" rel="noreferrer">http://127.0.0.1:9527/restful/123</a></li><li>指定方法的 MVC restful 路由 <a href="http://127.0.0.1:9527/restful/123/show" target="_blank" rel="noreferrer">http://127.0.0.1:9527/restful/123/show</a></li><li>注解路由 <a href="http://127.0.0.1:9527/api/v1/petLeevelForApi/helloworld" target="_blank" rel="noreferrer">http://127.0.0.1:9527/api/v1/petLeevelForApi/helloworld</a></li><li>带有绑定的注解路由 <a href="http://127.0.0.1:9527/api/v2/withBind/foobar" target="_blank" rel="noreferrer">http://127.0.0.1:9527/api/v2/withBind/foobar</a></li><li>php leevel link:public <a href="http://127.0.0.1:9527/public/css/page.css" target="_blank" rel="noreferrer">http://127.0.0.1:9527/public/css/page.css</a></li><li>php leevel link:storage <a href="http://127.0.0.1:9527/storage/logo.png" target="_blank" rel="noreferrer">http://127.0.0.1:9527/storage/logo.png</a></li><li>php leevel link:apis <a href="http://127.0.0.1:9527/apis/" target="_blank" rel="noreferrer">http://127.0.0.1:9527/apis/</a></li><li>php leevel link:debugbar <a href="http://127.0.0.1:9527/debugbar/debugbar.css" target="_blank" rel="noreferrer">http://127.0.0.1:9527/debugbar/debugbar.css</a></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>QueryPHP 在 composer 安装过程中自动运行了创建软连接的命令将一些非 Web 根目录的站点映射到根目录， 这样我们可以使用内置的服务来访问这些链接。这些服务包含: 公共资源（public）、上传文件（storage）、 Swagger Api（apis）、Debugbar 调试（debugbar）。</p></div><h2 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置">¶</a></h2><p>QueryPHP 在初始化应用程序会自动帮您创建 <code>.env</code>、<code>.env.phpunit</code> 文件。</p><ul><li>.env (环境配置)</li><li>.env.phpunit (单元测试环境配置)</li></ul><h3 id="入口目录" tabindex="-1">入口目录 <a class="header-anchor" href="#入口目录">¶</a></h3><p>您必须将 Web 站点的根目录指向 <code>www</code> 目录，其中 <code>index.php</code> 是整个应用的单一入口文件，例如 Nginx。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">root /data/codes/queryphp/www;</span></span>
<span class="line"><span style="color:#A6ACCD;">index index.html index.php;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h3 id="目录权限" tabindex="-1">目录权限 <a class="header-anchor" href="#目录权限">¶</a></h3><p>系统有几个目录需要配置写入权限 <code>storage</code>。</p><h2 id="搭建站点" tabindex="-1">搭建站点 <a class="header-anchor" href="#搭建站点">¶</a></h2><p>首先需要创建一个站点的配置文件,例如 <code>/server/nginx-1.6.2/vhosts/queryphp.conf</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">server {</span></span>
<span class="line"><span style="color:#A6ACCD;">    add_header HostName php-7.4.0-app1;</span></span>
<span class="line"><span style="color:#A6ACCD;">    listen 8080;</span></span>
<span class="line"><span style="color:#A6ACCD;">    server_name queryphp.cn  *.queryphp.cn;</span></span>
<span class="line"><span style="color:#A6ACCD;">    error_log  /var/log/nginx/queryphp.error.log;</span></span>
<span class="line"><span style="color:#A6ACCD;">    access_log /var/log/nginx/queryphp.access.log main;</span></span>
<span class="line"><span style="color:#A6ACCD;">    root /data/codes/queryphp/www;</span></span>
<span class="line"><span style="color:#A6ACCD;">    index  index.html index.php;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    location / {</span></span>
<span class="line"><span style="color:#A6ACCD;">       try_files $uri $uri/ /index.php?$query_string;</span></span>
<span class="line"><span style="color:#A6ACCD;">    }</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    location ~ \\.php$ {</span></span>
<span class="line"><span style="color:#A6ACCD;">        fastcgi_split_path_info ^(.+\\.php)(/.+)$;</span></span>
<span class="line"><span style="color:#A6ACCD;">        fastcgi_pass 127.0.0.1:9000;</span></span>
<span class="line"><span style="color:#A6ACCD;">        fastcgi_index index.php;</span></span>
<span class="line"><span style="color:#A6ACCD;">        include fastcgi_params;</span></span>
<span class="line"><span style="color:#A6ACCD;">        fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;</span></span>
<span class="line"><span style="color:#A6ACCD;">    }</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    location ~ /nginx_status$ {</span></span>
<span class="line"><span style="color:#A6ACCD;">        stub_status on;</span></span>
<span class="line"><span style="color:#A6ACCD;">        access_log off;</span></span>
<span class="line"><span style="color:#A6ACCD;">        allow  all;</span></span>
<span class="line"><span style="color:#A6ACCD;">    }</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>笔者因为会在 Mac 中将端口转发到虚拟机中的 8080 端口，您的开发环境直接配置 80 端口即可。</p></div><p>修改虚拟机 <code>/etc/hosts</code>,添加几个测试域名，后面 <code>vip</code> 这些主要用于调试路由域名匹配，可以不要 。 Mac 系统的 <code>/etc/hosts</code> 也需要添加这些如下域名。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">127.0.0.1      queryphp.cn</span></span>
<span class="line"><span style="color:#A6ACCD;">127.0.0.1      www.queryphp.cn</span></span>
<span class="line"><span style="color:#A6ACCD;">127.0.0.1      test.queryphp.cn</span></span>
<span class="line"><span style="color:#A6ACCD;">127.0.0.1      vip.queryphp.cn</span></span>
<span class="line"><span style="color:#A6ACCD;">127.0.0.1      x.vip.queryphp.cn</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>刷新虚拟机 Ubuntu 网络使域名生效</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">/etc/rc.d/init.d/network</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">restart</span></span>
<span class="line"></span></code></pre></div><p>重启 <code>Nginx</code></p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">service</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nginx</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">restart</span></span>
<span class="line"></span></code></pre></div><p>访问地址</p><ul><li>首页 <a href="http://queryphp.cn/" target="_blank" rel="noreferrer">http://queryphp.cn/</a></li><li>MVC 路由 <a href="http://queryphp.cn/api/test" target="_blank" rel="noreferrer">http://queryphp.cn/api/test</a></li><li>MVC restful 路由 <a href="http://queryphp.cn/restful/123" target="_blank" rel="noreferrer">http://queryphp.cn/restful/123</a></li><li>指定方法的 MVC restful 路由 <a href="http://queryphp.cn/restful/123/show" target="_blank" rel="noreferrer">http://queryphp.cn/restful/123/show</a></li><li>注解路由 <a href="http://queryphp.cn/api/v1/petLeevelForApi/helloworld" target="_blank" rel="noreferrer">http://queryphp.cn/api/v1/petLeevelForApi/helloworld</a></li><li>带有绑定的注解路由 <a href="http://queryphp.cn/api/v2/withBind/foobar" target="_blank" rel="noreferrer">http://queryphp.cn/api/v2/withBind/foobar</a></li><li>php leevel link:public <a href="http://queryphp.cn/public/css/page.css" target="_blank" rel="noreferrer">http://queryphp.cn/public/css/page.css</a></li><li>php leevel link:storage <a href="http://queryphp.cn/storage/logo.png" target="_blank" rel="noreferrer">http://queryphp.cn/storage/logo.png</a></li><li>php leevel link:apis <a href="http://queryphp.cn/apis/" target="_blank" rel="noreferrer">http://queryphp.cn/apis/</a></li><li>php leevel link:debugbar <a href="http://queryphp.cn/debugbar/debugbar.css" target="_blank" rel="noreferrer">http://queryphp.cn/debugbar/debugbar.css</a></li></ul><h3 id="apache" tabindex="-1">Apache <a class="header-anchor" href="#apache">¶</a></h3><p>Web 根目录已经内置了 <code>www/.htaccess</code> 文件来为隐藏 index.php,需要启用 mod_rewrite 模块。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">&lt;IfModule mod_rewrite.c&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    &lt;IfModule mod_negotiation.c&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        Options -MultiViews -Indexes</span></span>
<span class="line"><span style="color:#A6ACCD;">    &lt;/IfModule&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteEngine On</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteCond %{HTTP:Authorization} .</span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteRule .* - [E=HTTP_AUTHORIZATION:%{HTTP:Authorization}]</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteCond %{REQUEST_FILENAME} !-d</span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteCond %{REQUEST_FILENAME} !-f</span></span>
<span class="line"><span style="color:#A6ACCD;">    RewriteRule ^(.*)$ index.php/$1 [QSA,PT,L]</span></span>
<span class="line"><span style="color:#A6ACCD;">&lt;/IfModule&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div>`,48),t=[p];function r(o,c,i,h,C,d){return e(),a("div",null,t)}const A=s(l,[["render",r]]);export{u as __pageData,A as default};
